"use strict";

const { spawn } = require("child_process");

function launchSession(prompt, options = {}) {
  return new Promise((resolve) => {
    const args = [
      "-p",
      prompt,
      "--output-format",
      "stream-json",
      "--dangerously-skip-permissions",
    ];

    if (options.model) {
      args.push("--model", options.model);
    }

    if (options.maxTurns) {
      args.push("--max-turns", String(options.maxTurns));
    }

    if (options.maxBudget) {
      args.push("--max-budget-usd", String(options.maxBudget));
    }

    const cwd = options.cwd || process.cwd();
    const proc = spawn("claude", args, {
      cwd,
      stdio: ["ignore", "pipe", "pipe"],
      env: { ...process.env },
    });

    let buffer = "";
    let resultData = null;
    let lastStopReason = null;
    const startTime = Date.now();

    proc.stdout.on("data", (chunk) => {
      buffer += chunk.toString();
      const lines = buffer.split("\n");
      buffer = lines.pop();

      for (const line of lines) {
        if (!line.trim()) continue;
        let event;
        try {
          event = JSON.parse(line);
        } catch {
          continue;
        }

        if (event.type === "assistant" && event.message) {
          const msg = event.message;
          if (msg.stop_reason) {
            lastStopReason = msg.stop_reason;
          }
          for (const block of msg.content || []) {
            if (block.type === "text" && block.text) {
              process.stderr.write(block.text);
              if (!block.text.endsWith("\n")) {
                process.stderr.write("\n");
              }
            } else if (block.type === "tool_use") {
              process.stderr.write(`[tool: ${block.name}]`);
              if (block.input) {
                const preview = JSON.stringify(block.input);
                if (preview.length <= 200) {
                  process.stderr.write(` ${preview}`);
                }
              }
              process.stderr.write("\n");
            }
          }
        } else if (event.type === "tool_result" || event.type === "user") {
          // tool results — optionally show errors
          const msg = event.message;
          if (msg && msg.content) {
            for (const block of msg.content || []) {
              if (block.is_error && block.type === "tool_result") {
                process.stderr.write(`[tool error: ${block.content || "unknown"}]\n`);
              }
            }
          }
        } else if (event.type === "result") {
          resultData = event;
        }
      }
    });

    proc.stderr.on("data", (chunk) => {
      process.stderr.write(chunk);
    });

    proc.on("error", (err) => {
      const elapsed = Date.now() - startTime;
      resolve(buildReport(null, 1, lastStopReason, elapsed, err.message));
    });

    proc.on("close", (code) => {
      // process any remaining buffer
      if (buffer.trim()) {
        try {
          const event = JSON.parse(buffer);
          if (event.type === "result") {
            resultData = event;
          }
          if (event.type === "assistant" && event.message && event.message.stop_reason) {
            lastStopReason = event.message.stop_reason;
          }
        } catch {
          // ignore
        }
      }

      const elapsed = Date.now() - startTime;
      resolve(buildReport(resultData, code || 0, lastStopReason, elapsed));
    });
  });
}

function buildReport(resultData, exitCode, lastStopReason, fallbackDuration, errorMsg) {
  if (!resultData) {
    return {
      exitCode,
      result: errorMsg || "",
      totalCost: 0,
      durationMs: fallbackDuration || 0,
      numTurns: 0,
      stopReason: lastStopReason || "error",
      stopReasonSubtype: "error",
      usage: {
        inputTokens: 0,
        outputTokens: 0,
        cacheCreationInputTokens: 0,
        cacheReadInputTokens: 0,
      },
      modelUsage: {},
    };
  }

  const usage = resultData.usage || {};
  const modelUsageSrc = resultData.model_usage || resultData.modelUsage || {};

  const modelUsage = {};
  for (const [model, stats] of Object.entries(modelUsageSrc)) {
    modelUsage[model] = {
      costUsd: stats.cost_usd ?? stats.costUsd ?? 0,
      inputTokens: stats.input_tokens ?? stats.inputTokens ?? 0,
      outputTokens: stats.output_tokens ?? stats.outputTokens ?? 0,
      cacheCreationInputTokens:
        stats.cache_creation_input_tokens ?? stats.cacheCreationInputTokens ?? 0,
      cacheReadInputTokens:
        stats.cache_read_input_tokens ?? stats.cacheReadInputTokens ?? 0,
    };
  }

  return {
    exitCode,
    result: resultData.result || "",
    totalCost:
      resultData.cost_usd ?? resultData.total_cost_usd ?? resultData.totalCost ?? 0,
    durationMs: resultData.duration_ms ?? resultData.durationMs ?? fallbackDuration ?? 0,
    numTurns: resultData.num_turns ?? resultData.numTurns ?? 0,
    stopReason: lastStopReason || resultData.stop_reason || "end_turn",
    stopReasonSubtype: resultData.subtype || "success",
    usage: {
      inputTokens: usage.input_tokens ?? usage.inputTokens ?? 0,
      outputTokens: usage.output_tokens ?? usage.outputTokens ?? 0,
      cacheCreationInputTokens:
        usage.cache_creation_input_tokens ?? usage.cacheCreationInputTokens ?? 0,
      cacheReadInputTokens:
        usage.cache_read_input_tokens ?? usage.cacheReadInputTokens ?? 0,
    },
    modelUsage,
  };
}

module.exports = { launchSession };

